code = """import json, pandas as pd
cases = pd.DataFrame(var_call_neQv4XuJHh3Oft8ZXlGiKNrQ)
# filter to past 4 months relative to 2023-09-02: from 2023-05-02 to 2023-09-02
cases['createddate'] = pd.to_datetime(cases['createddate'].str.replace('None', ''))
mask = (cases['createddate'] >= pd.Timestamp('2023-05-02')) & (cases['createddate'] < pd.Timestamp('2023-09-02'))
cases = cases[mask]
# exclude transferred-out cases: in this dataset, no transfer history was returned, so all are single-owner; handle closed only
cases = cases[cases['closeddate'] != 'None']
cases['closeddate'] = pd.to_datetime(cases['closeddate'])
handle = (cases['closeddate'] - cases['createddate']).dt.total_seconds()/60.0
cases['handle_minutes'] = handle
agg = cases.groupby('agent_id').agg(cases_handled=('case_id','count'), avg_handle=('handle_minutes','mean')).reset_index()
agg = agg[agg['cases_handled']>1]
if agg.empty:
    result = None
else:
    best = agg.sort_values('avg_handle').iloc[0]['agent_id']
    result = best
out = json.dumps(result)
print('__RESULT__:')
print(out)"""

